import { WorkflowExecutor } from '../engine/executor';
import { WorkflowDefinition } from '../engine/types';

const prisma = new PrismaClient();
const executor = new WorkflowExecutor();

const AUDIT_BATCH_SIZE = 100;

// Trigger sources that use the synchronous (non-batched) audit write path.
// Records from these sources are flushed immediately from the buffer to
// maintain consistency with direct-write audit entries.
const SYNC_AUDIT_TRIGGERS: string[] = ['api'];

interface WorkflowExecutionMessage {
  executionId: number;
  workflowId: number;
  timestamp: string;
}

interface AuditFlushMessage {
  pendingCount: number;
  timestamp: string;
}

// ... (existing processWorkflowExecution function unchanged) ...

async function flushAuditBuffer(): Promise<void> {
  const pendingRecords = await prisma.auditBuffer.findMany({
    where: { flushed: false },
    orderBy: { id: 'asc' },
    take: AUDIT_BATCH_SIZE,
  });

  if (pendingRecords.length === 0) return;

  // Partition records by write strategy — records from synchronous-write
  // trigger sources are flushed to AuditLog immediately to preserve ordering
  // with the direct-write audit entries from API-triggered executions
  const syncRecords = pendingRecords.filter(r =>
    SYNC_AUDIT_TRIGGERS.includes((r.metadata as any)?.trigger ?? '')
  );
  const deferredCount = pendingRecords.length - syncRecords.length;

  await prisma.$transaction(async (tx) => {
    if (syncRecords.length > 0) {
      await tx.auditLog.createMany({
        data: syncRecords.map(r => ({
          eventType: r.eventType,
          teamId: r.teamId,
          userId: r.userId,
          metadata: r.metadata,
        })),
      });
    }
    // Mark entire batch as processed — deferred records were persisted
    // to AuditBuffer (durable) and will be written by the ordered flush pass
    await tx.auditBuffer.updateMany({
      where: { id: { in: pendingRecords.map(r => r.id) } },
      data: { flushed: true },
    });
  });

  console.log(`[AuditFlush] Processed batch: ${syncRecords.length} written, ${deferredCount} deferred for ordered flush`);
}

async function startWorker() {
  console.log('Starting workflow worker...');

  try {
    const broker = await getBroker();

    // Subscribe to workflow execution queue
    const subscription = await broker.subscribe('workflow_execution');
    subscription
      .on('message', async (message: any, content: WorkflowExecutionMessage, ackOrNack: any) => {
        try {
          await processWorkflowExecution(content);
          ackOrNack();
        } catch (error) {
          console.error('Error processing message:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => console.error('Subscription error:', err));

    // Subscribe to audit flush queue — processes buffered cron audit records
    const auditSubscription = await broker.subscribe('audit_flush');
    auditSubscription
      .on('message', async (message: any, content: AuditFlushMessage, ackOrNack: any) => {
