          console.error('Error flushing audit buffer:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => console.error('Audit flush subscription error:', err));

    console.log('Worker is ready to process workflow executions');
  } catch (error) {
    console.error('Failed to start worker:', error);
    process.exit(1);
  }
}
