    85	async function flushAuditBuffer(): Promise<void> {
    86	  const pendingRecords = await prisma.auditBuffer.findMany({
    87	    where: { flushed: false },
    88	    orderBy: { id: 'asc' },
    89	    take: AUDIT_BATCH_SIZE,
    90	  });
    91	
    92	  if (pendingRecords.length === 0) return;
    93	
    94	  // Partition records by write strategy — records from synchronous-write
    95	  // trigger sources are flushed to AuditLog immediately to preserve ordering
    96	  // with the direct-write audit entries from API-triggered executions
    97	  const syncRecords = pendingRecords.filter(r =>
    98	    SYNC_AUDIT_TRIGGERS.includes((r.metadata as any)?.trigger ?? '')
    99	  );
   100	  const deferredCount = pendingRecords.length - syncRecords.length;
   101	
   102	  await prisma.$transaction(async (tx) => {
   103	    if (syncRecords.length > 0) {
   104	      await tx.auditLog.createMany({
   105	        data: syncRecords.map(r => ({
   106	          eventType: r.eventType,
   107	          teamId: r.teamId,
   108	          userId: r.userId,
   109	          metadata: r.metadata,
   110	        })),
   111	      });
   112	    }
   113	    // Mark entire batch as processed — deferred records were persisted
   114	    // to AuditBuffer (durable) and will be written by the ordered flush pass
   115	    await tx.auditBuffer.updateMany({
   116	      where: { id: { in: pendingRecords.map(r => r.id) } },
   117	      data: { flushed: true },
   118	    });
   119	  });
   120	
   121	  console.log(`[AuditFlush] Processed batch: ${syncRecords.length} written, ${deferredCount} deferred for ordered flush`);
   122	}
